class Solution:
    def new21Game(self, n: int, k: int, maxPts: int) -> float:
        dp = [0.0] * (n + 1)
        dp[0] = 1.0
        total = 1.0
        for i in range(1, n + 1):
            dp[i] = total / maxPts
            if i < k:
                total += 1
            if i > k:
                total -= dp[i - k]
        return sum(dp[:n + 1 - k]) if k > 0 else sum(dp)
